class MovingAverage:
    def __init__(self, size):
        self.q = deque(maxlen=size)
        self.s = 0
    def next(self, val):
        if len(self.q) == self.q.maxlen:
            self.s -= self.q[0]
        self.q.append(val)
        self.s += val
        return self.s / len(self.q)

