def hash_join(left, right, lkey, rkey):
    idx = defaultdict(list)
    for r in right:
        idx[r[rkey]].append(r)
    out = []
    for l in left:
        for r in idx.get(l[lkey], []):
            out.append({**l, **r})
    return out

from collections import deque

class Deduplicator:
    def __init__(self, ttl_seconds):
        self.ttl = ttl_seconds
        self.seen = {}
        self.q = deque()
    def is_new(self, event_id, ts):
        # evict expired
        while self.q and self.q[0][1] + self.ttl < ts:
            eid, _ = self.q.popleft()
            self.seen.pop(eid, None)
        if event_id in self.seen:
            return False
        self.seen[event_id] = ts
        self.q.append((event_id, ts))
        return True

