class WordDictionary:
    def __init__(self):
        self.r = {}
    def addWord(self, w):
        n = self.r
        for c in w: n = n.setdefault(c, {})
        n['#'] = True
    def search(self, w):
        def dfs(i, n):
            if i == len(w): return '#' in n
            c = w[i]
            if c == '.':
                return any(k != '#' and dfs(i + 1, n[k]) for k in n)
            return c in n and dfs(i + 1, n[c])
        return dfs(0, self.r)

class Trie:
    def __init__(self): self.r = {}
    def insert(self, w):
        n = self.r
        for c in w: n = n.setdefault(c, {})
        n['#'] = True
    def _walk(self, w):
        n = self.r
        for c in w:
            if c not in n: return None
            n = n[c]
        return n
    def search(self, w):
        n = self._walk(w); return bool(n) and '#' in n
    def startsWith(self, p):
        return self._walk(p) is not None

