        while parent[x] != x:
            parent[x] = parent[parent[x]]; x = parent[x]
        return x
    email_name = {}
    for acc in accounts:
        name = acc[0]
        for e in acc[1:]:
            parent.setdefault(e, e); email_name[e] = name
            parent[find(e)] = find(acc[1])
