    keys = {'2':'abc','3':'def','4':'ghi','5':'jkl','6':'mno','7':'pqrs','8':'tuv','9':'wxyz'}
    res = ['']
    for d in digits:
        res = [p + c for p in res for c in keys[d]]
    return res

def numIslands(grid):
    if not grid: return 0
    R, C = len(grid), len(grid[0]); count = 0
    def dfs(r, c):
        if r<0 or c<0 or r>=R or c>=C or grid[r][c] != '1': return
        grid[r][c] = '0'
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]: dfs(r+dr, c+dc)
    for r in range(R):
        for c in range(C):
            if grid[r][c] == '1': count += 1; dfs(r, c)
    return count

def cloneGraph(node):
    if not node: return None
    seen = {}
    def dfs(n):
        if n in seen: return seen[n]
        copy = Node(n.val); seen[n] = copy
        for nei in n.neighbors: copy.neighbors.append(dfs(nei))
        return copy
    return dfs(node)

def maxAreaOfIsland(grid):
    if not grid: return 0
    R, C = len(grid), len(grid[0]); best = 0
    def dfs(r, c):
        if r<0 or c<0 or r>=R or c>=C or grid[r][c] != 1: return 0
        grid[r][c] = 0
        return 1 + dfs(r+1,c) + dfs(r-1,c) + dfs(r,c+1) + dfs(r,c-1)
    for r in range(R):
        for c in range(C):
            if grid[r][c] == 1: best = max(best, dfs(r, c))
    return best

def pacificAtlantic(h):
    if not h: return []
    R, C = len(h), len(h[0]); pac, atl = set(), set()
    def dfs(r, c, seen, prev):
        if (r, c) in seen or r<0 or c<0 or r>=R or c>=C or h[r][c] < prev: return
        seen.add((r, c))
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]: dfs(r+dr, c+dc, seen, h[r][c])
    for r in range(R): dfs(r, 0, pac, 0); dfs(r, C-1, atl, 0)
    for c in range(C): dfs(0, c, pac, 0); dfs(R-1, c, atl, 0)
    return list(pac & atl)

def solve(board):
    if not board: return
    R, C = len(board), len(board[0])
    def dfs(r, c):
        if r<0 or c<0 or r>=R or c>=C or board[r][c] != 'O': return
        board[r][c] = '#'
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]: dfs(r+dr, c+dc)
    for r in range(R): dfs(r, 0); dfs(r, C-1)
    for c in range(C): dfs(0, c); dfs(R-1, c)
    for r in range(R):
        for c in range(C):
            board[r][c] = 'O' if board[r][c] == '#' else 'X'

