from collections import defaultdict, deque

def canFinish(n, prereq):
    g = defaultdict(list); deg = [0] * n
    for a, b in prereq: g[b].append(a); deg[a] += 1
    q = deque([i for i in range(n) if deg[i] == 0]); done = 0
    while q:
        x = q.popleft(); done += 1
        for y in g[x]:
            deg[y] -= 1
            if deg[y] == 0: q.append(y)
    return done == n

from collections import defaultdict, deque

def findOrder(n, prereq):
    g = defaultdict(list); deg = [0] * n
    for a, b in prereq: g[b].append(a); deg[a] += 1
    q = deque([i for i in range(n) if deg[i] == 0]); order = []
    while q:
        x = q.popleft(); order.append(x)
        for y in g[x]:
            deg[y] -= 1
            if deg[y] == 0: q.append(y)
    return order if len(order) == n else []

def findRedundantConnection(edges):
    parent = list(range(len(edges) + 1))
    def find(x):
        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x
    for a, b in edges:
        ra, rb = find(a), find(b)
        if ra == rb: return [a, b]
        parent[ra] = rb

def countComponents(n, edges):
    parent = list(range(n))
    def find(x):
        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x
    for a, b in edges:
        ra, rb = find(a), find(b)
        if ra != rb: parent[ra] = rb
    return len({find(i) for i in range(n)})

import heapq

def minCostConnectPoints(points):
    n = len(points); seen = {0}; total = 0
    h = [(abs(points[0][0] - points[j][0]) + abs(points[0][1] - points[j][1]), j) for j in range(1, n)]
    heapq.heapify(h)
    while len(seen) < n:
        d, u = heapq.heappop(h)
        if u in seen: continue
        seen.add(u); total += d
        for v in range(n):
            if v not in seen:
                heapq.heappush(h, (abs(points[u][0]-points[v][0]) + abs(points[u][1]-points[v][1]), v))
    return total

